('frances', 'bachillerato', '{1}', 'Le château de Chambord est le plus grand château de la Loire et a été construit pendant la Renaissance française');
INSERT INTO detective_sentences (subject_id, level, grades, sentence) VALUES
('frances', 'bachillerato', '{2}', 'Albert Camus a écrit L''Étranger un roman existentialiste qui explore l''absurdité de la condition humaine moderne'),
('frances', 'bachillerato', '{2}', 'Simone de Beauvoir a publié Le Deuxième Sexe un essai fondateur du féminisme contemporain en mil neuf cent quarante-neuf'),
('frances', 'bachillerato', '{2}', 'Marcel Proust a écrit À la recherche du temps perdu une œuvre monumentale sur la mémoire et le temps qui passe'),
('frances', 'bachillerato', '{2}', 'La Belle Époque désigne la période d''optimisme et de progrès culturel en France entre mil huit cent soixante-dix et la Première Guerre'),
('frances', 'bachillerato', '{2}', 'René Descartes a formulé le célèbre principe je pense donc je suis qui fonde la philosophie moderne occidentale'),
('frances', 'bachillerato', '{2}', 'Charles Baudelaire a publié Les Fleurs du mal une œuvre poétique qui a scandalisé la société bourgeoise de son époque'),
('frances', 'bachillerato', '{2}', 'Michel Foucault a analysé les mécanismes du pouvoir et du savoir dans des ouvrages comme Surveiller et punir'),
('frances', 'bachillerato', '{2}', 'Voltaire a défendu la tolérance et la liberté d''expression dans ses contes philosophiques comme Candide ou l''optimisme'),
('frances', 'bachillerato', '{2}', 'Arthur Rimbaud a révolutionné la poésie française avec des œuvres comme Le Bateau ivre avant d''abandonner la littérature'),
('frances', 'bachillerato', '{2}', 'Jean-Jacques Rousseau a développé l''idée du contrat social qui a profondément influencé la Révolution française'),
('frances', 'bachillerato', '{2}', 'André Breton a fondé le mouvement surréaliste qui voulait libérer l''imagination et l''inconscient de toute contrainte rationnelle'),
('frances', 'bachillerato', '{2}', 'Jean-Luc Godard a été l''une des figures principales de la Nouvelle Vague qui a révolutionné le cinéma français'),
('frances', 'bachillerato', '{2}', 'Guy de Maupassant a écrit des centaines de nouvelles qui dépeignent avec précision la société française du dix-neuvième siècle'),
('frances', 'bachillerato', '{2}', 'La philosophie des Lumières a préparé intellectuellement la Révolution avec des penseurs comme Montesquieu et Diderot'),
('frances', 'bachillerato', '{2}', 'Mai soixante-huit a été un mouvement social et culturel qui a profondément transformé la société française contemporaine'),
('frances', 'bachillerato', '{2}', 'Paul Verlaine et Arthur Rimbaud ont entretenu une relation tumultueuse qui a marqué la poésie symboliste française'),
('frances', 'bachillerato', '{2}', 'Emmanuel Macron est devenu président de la République française en deux mille dix-sept à l''âge de trente-neuf ans'),
('frances', 'bachillerato', '{2}', 'Le structuralisme est un courant intellectuel développé en France par des penseurs comme Claude Lévi-Strauss et Roland Barthes'),
('frances', 'bachillerato', '{2}', 'Édith Piaf a incarné l''âme populaire française avec des chansons inoubliables sur l''amour et la souffrance humaine'),
('frances', 'bachillerato', '{2}', 'Louis Aragon a été un poète surréaliste puis engagé qui a célébré l''amour et la Résistance dans ses œuvres'),
('frances', 'bachillerato', '{2}', 'La laïcité est un principe fondamental de la République française qui sépare strictement l''État et les religions'),
('frances', 'bachillerato', '{2}', 'Jacques Derrida a fondé la déconstruction un courant philosophique qui remet en question les oppositions binaires traditionnelles'),
('frances', 'bachillerato', '{2}', 'L''Académie française a été créée par le cardinal de Richelieu pour veiller sur la langue française et son évolution'),
('frances', 'bachillerato', '{2}', 'Stéphane Mallarmé a développé une poésie symboliste hermétique qui cherche à suggérer plutôt qu''à décrire directement'),
('frances', 'bachillerato', '{2}', 'La Quatrième République française a été marquée par l''instabilité gouvernementale et la décolonisation difficile'),
('frances', 'bachillerato', '{2}', 'Pierre Bourdieu a analysé les mécanismes de reproduction sociale et culturelle dans la société française contemporaine'),
('frances', 'bachillerato', '{2}', 'André Malraux a été ministre de la Culture sous de Gaulle et a créé les Maisons de la Culture dans toute la France'),
('frances', 'bachillerato', '{2}', 'Françoise Sagan a publié Bonjour tristesse à dix-huit ans et ce roman est devenu un symbole de la jeunesse libérée'),
('frances', 'bachillerato', '{2}', 'L''affaire Dreyfus a profondément divisé la société française entre la fin du dix-neuvième et le début du vingtième siècle'),
('frances', 'bachillerato', '{2}', 'Marguerite Duras a écrit L''Amant un roman autobiographique qui a obtenu le prix Goncourt en mil neuf cent quatre-vingt-quatre'),
('frances', 'bachillerato', '{2}', 'Le nouveau roman est un mouvement littéraire qui a rejeté les conventions narratives traditionnelles dans les années cinquante'),
('frances', 'bachillerato', '{2}', 'Georges Pompidou a succédé à de Gaulle à la présidence et a lancé le projet culturel du centre Beaubourg à Paris'),
('frances', 'bachillerato', '{2}', 'Annie Ernaux a reçu le prix Nobel de littérature en deux mille vingt-deux pour son œuvre autobiographique et sociologique'),
('frances', 'bachillerato', '{2}', 'Le colonialisme français en Algérie a entraîné une guerre sanglante qui s''est terminée par l''indépendance en mil neuf cent soixante-deux'),
('frances', 'bachillerato', '{2}', 'Claude Debussy a composé des œuvres impressionnistes comme La Mer qui ont renouvelé complètement le langage musical'),
('frances', 'bachillerato', '{2}', 'Jean Renoir a réalisé La Règle du jeu un film considéré comme l''un des chefs-d''œuvre absolus du cinéma mondial'),
('frances', 'bachillerato', '{2}', 'Le mouvement des gilets jaunes a commencé en deux mille dix-huit comme une protestation contre la hausse des taxes sur le carburant'),
('frances', 'bachillerato', '{2}', 'Olympe de Gouges a rédigé la Déclaration des droits de la femme pendant la Révolution française et a été guillotinée ensuite'),
('frances', 'bachillerato', '{2}', 'Michel Houellebecq est un écrivain contemporain controversé qui explore l''aliénation de l''individu dans la société occidentale moderne'),
('frances', 'bachillerato', '{2}', 'La Cinquième République a été fondée par Charles de Gaulle en mil neuf cent cinquante-huit avec une constitution très présidentielle');
INSERT INTO detective_sentences (subject_id, level, grades, sentence) VALUES
('valenciano', 'bachillerato', '{1}', 'Ausiàs March és considerat el poeta més important de la literatura valenciana medieval del segle quinze'),
('valenciano', 'bachillerato', '{1}', 'Joanot Martorell va escriure el Tirant lo Blanc una de les primeres novel·les modernes de la literatura europea'),
('valenciano', 'bachillerato', '{1}', 'El Segle d''Or valencià correspon al segle quinze quan València era una de les ciutats més riques de la Mediterrània'),
('valenciano', 'bachillerato', '{1}', 'Jaume el Conqueridor va fundar el Regne de València l''any mil dos-cents trenta-huit després de la conquesta cristiana'),
('valenciano', 'bachillerato', '{1}', 'La Llotja de la Seda de València és una obra mestra de l''arquitectura gòtica civil declarada Patrimoni de la Humanitat'),
('valenciano', 'bachillerato', '{1}', 'Sant Vicent Ferrer va ser un predicador valencià famós per la seua eloqüència i els seus sermons públics medievals'),
('valenciano', 'bachillerato', '{1}', 'Jordi de Sant Jordi va ser un poeta valencià del segle quinze que va escriure en la tradició trobadoresca occitana'),
('valenciano', 'bachillerato', '{1}', 'La Renaixença va ser un moviment cultural del segle dinou que va recuperar l''ús literari de la llengua valenciana'),
('valenciano', 'bachillerato', '{1}', 'Teodor Llorente és considerat el patriarca de la Renaixença valenciana i va fundar el diari Las Provincias'),
('valenciano', 'bachillerato', '{1}', 'Les Normes de Castelló de l''any mil nou-cents trenta-dos van establir les regles ortogràfiques del valencià modern'),
('valenciano', 'bachillerato', '{1}', 'Vicent Andrés Estellés és un dels poetes valencians més importants del segle vint amb una obra immensa'),
('valenciano', 'bachillerato', '{1}', 'La ciutat de València va ser fundada pels romans l''any cent trenta-huit abans de Crist amb el nom de Valentia Edetanorum'),
('valenciano', 'bachillerato', '{1}', 'Les Falles de València són una festa declarada Patrimoni Cultural Immaterial de la Humanitat per la Unesco'),
('valenciano', 'bachillerato', '{1}', 'Sor Isabel de Villena va escriure la Vita Christi una obra religiosa important de la literatura medieval valenciana'),
('valenciano', 'bachillerato', '{1}', 'Joan Roís de Corella va ser un escriptor valencià del segle quinze influït per l''humanisme renaixentista italià'),
('valenciano', 'bachillerato', '{1}', 'La Catedral de València conserva el Sant Calze que segons la tradició és el utilitzat per Jesucrist en l''Últim Sopar'),
('valenciano', 'bachillerato', '{1}', 'Roís de Corella va escriure la Tragèdia de Caldesa una obra que barreja elements clàssics amb la tradició cavalleresca'),
('valenciano', 'bachillerato', '{1}', 'La llengua valenciana forma part del diasistema lingüístic compartit amb el català i el balear amb les seues varietats pròpies'),
('valenciano', 'bachillerato', '{1}', 'El Misteri d''Elx és una representació medieval conservada ininterrompudament i declarada Patrimoni de la Humanitat'),
